import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../assets/styles/Skype.css'; // Presupunem că stilurile pentru Skype se vor afla aici

const Skype = ({ onClose }) => {
  const [errorMessage, setErrorMessage] = useState('');
  const [backendUrl, setBackendUrl] = useState('');
  const [serverInfo, setServerInfo] = useState({ ip: '', port: '' });

  useEffect(() => {
    fetchBackendUrl();
  }, []);

  const fetchBackendUrl = async () => {
    try {
      const response = await axios.get('/api/server-info');
      const { ip, port } = response.data;
      const url = `http://${ip}:${port}`;
      setBackendUrl(url);
      setServerInfo({ ip, port });
    } catch (error) {
      console.error('There was an error fetching the backend URL!', error);
    }
  };

  const handleOpenSkype = () => {
    axios.post(`${backendUrl}/shortcuts/skype/open-skype/`)
      .then(response => {
        console.log(response.data.message || 'Skype opened successfully');
        setErrorMessage(''); // Resetăm orice eroare
      })
      .catch(error => {
        console.error('There was an error opening Skype!', error);
        setErrorMessage('There was an error opening Skype.');
      });
  };

  const handleCloseSkype = () => {
    axios.post(`${backendUrl}/shortcuts/skype/close-skype/`)
      .then(response => {
        console.log(response.data.message || 'Skype closed successfully');
        setErrorMessage('');
        if (onClose) onClose(); // Dacă avem o funcție pentru a închide componenta, o apelăm
      })
      .catch(error => {
        console.error('There was an error closing Skype!', error);
        setErrorMessage('There was an error closing Skype.');
      });
  };

  return (
    <div className="skype-container">
      <h1 className="title">Skype</h1>
      <div className="button-container">
        <button onClick={handleOpenSkype} className="button open-skype-button">
          Open Skype
        </button>
        <button onClick={handleCloseSkype} className="button close-skype-button">
          Close Skype
        </button>
      </div>

      {errorMessage && (
        <div className="error-message">
          {errorMessage}
        </div>
      )}

      {/* Afișează informațiile serverului, pentru referință */}
      <div className="server-info">
        <p>IP Server: {serverInfo.ip}</p>
        <p>Port: {serverInfo.port}</p>
      </div>
    </div>
  );
};

export default Skype;
